import re

class Solution:
  def validateAnchorTag(self, tag: str) -> bool:
    if not isinstance(tag, str):
      return False
    if '<a' not in tag:
      return False
    regex = r'<a href="(.*?)" text="(.*?)">(.*?)</a>'
    match = re.match(regex, tag)
    if not match:
      return False
    if match.group(1) != '' and match.group(2) != '':
      return True
    return False

def main(s: str) -> None:
  solution = Solution()
  print(solution.validateAnchorTag('<a href="https://www.example.com" text="Click me">Click me</a>')) # true
  print(solution.validateAnchorTag('<a href="https://www.example.com"></a>')) # false
  print(solution.validateAnchorTag('<a text="Click me"></a>')) # false
  print(solution.validateAnchorTag('<a href="https://www.example.com" text="" text="Click me"></a>')) # false
  print(solution.validateAnchorTag('Invalid tag')) # false

if __name__ == '__main__':
  main('')
